import { Component } from '@angular/core';

@Component({
  selector: 'app-footer',
  templateUrl: './footer.component.html',
  styleUrls: ['./footer.component.scss']
})
export class FooterComponent {
  year = new Date().getFullYear();
}
<footer class="footer">
  <div class="container footer__inner">
    <span class="term-label">$ whoami</span>
    <p class="footer__text">Joyce Coem — Security &amp; Network Engineering</p>
    <div class="footer__links">
      <a href="https://linkedin.com/in/joyce-coem" target="_blank" rel="noopener">LinkedIn</a>
      <a href="https://github.com/JoyceCoem" target="_blank" rel="noopener">GitHub</a>
      <a href="https://medium.com/@joycecoem05" target="_blank" rel="noopener">Medium</a>
      <a href="mailto:joycecoem05@gmail.com">Email</a>
    </div>
    <p class="footer__copyright">&copy; {{ year }} Joyce Coem. Built with Angular &amp; ASP.NET Core.</p>
  </div>
</footer>
